# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
import json

# RabbitMQ Management API configuration
RABBITMQ_HOST = "localhost"
RABBITMQ_PORT = 15672
RABBITMQ_USER = "admin"
RABBITMQ_PASSWORD = "admin"

# Base URL for RabbitMQ Management API
BASE_URL = f"http://{RABBITMQ_HOST}:{RABBITMQ_PORT}/api"

def create_vhost(vhost_name):
    """Create a virtual host"""
    url = f"{BASE_URL}/vhosts/{vhost_name}"
    headers = {'Content-Type': 'application/json'}
    data = {"tracing": False}
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USER, RABBITMQ_PASSWORD), 
                              headers=headers, data=json.dumps(data))
        if response.status_code == 201:
            print(f"Virtual host '{vhost_name}' created successfully")
        else:
            print(f"Failed to create virtual host '{vhost_name}': {response.status_code} - {response.text}")
    except Exception as e:
        print(f"Error creating virtual host '{vhost_name}': {e}")

def create_user(username, password):
    """Create a user"""
    url = f"{BASE_URL}/users/{username}"
    headers = {'Content-Type': 'application/json'}
    data = {
        "password": password,
        "tags": ""
    }
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USER, RABBITMQ_PASSWORD), 
                              headers=headers, data=json.dumps(data))
        if response.status_code == 201:
            print(f"User '{username}' created successfully")
        else:
            print(f"Failed to create user '{username}': {response.status_code} - {response.text}")
    except Exception as e:
        print(f"Error creating user '{username}': {e}")

def set_permissions(username, vhost_name, configure_permissions, write_permissions, read_permissions):
    """Set permissions for a user on a virtual host"""
    url = f"{BASE_URL}/permissions/{vhost_name}/{username}"
    headers = {'Content-Type': 'application/json'}
    data = {
        "configure": configure_permissions,
        "write": write_permissions,
        "read": read_permissions
    }
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USER, RABBITMQ_PASSWORD), 
                              headers=headers, data=json.dumps(data))
        if response.status_code == 204:
            print(f"Permissions set for user '{username}' on vhost '{vhost_name}'")
        else:
            print(f"Failed to set permissions for user '{username}' on vhost '{vhost_name}': {response.status_code} - {response.text}")
    except Exception as e:
        print(f"Error setting permissions for user '{username}': {e}")

def setup_multitenant_environment():
    """Setup multi-tenant environment with vhosts and users"""
    
    # Define applications and their configurations
    applications = [
        {
            "name": "app1",
            "vhost": "/app1-vhost",
            "user": "app1_user",
            "password": "app1_password",
            "permissions": {
                "configure": ".*",
                "write": ".*",
                "read": ".*"
            }
        },
        {
            "name": "app2",
            "vhost": "/app2-vhost",
            "user": "app2_user",
            "password": "app2_password",
            "permissions": {
                "configure": ".*",
                "write": ".*",
                "read": ".*"
            }
        },
        {
            "name": "analytics",
            "vhost": "/analytics-vhost",
            "user": "analytics_user",
            "password": "analytics_password",
            "permissions": {
                "configure": ".*",
                "write": ".*",
                "read": ".*"
            }
        }
    ]
    
    # Create virtual hosts and users for each application
    for app in applications:
        # Create virtual host
        create_vhost(app["vhost"])
        
        # Create user
        create_user(app["user"], app["password"])
        
        # Set permissions
        set_permissions(app["user"], app["vhost"], 
                       app["permissions"]["configure"],
                       app["permissions"]["write"],
                       app["permissions"]["read"])

# Run the setup
if __name__ == "__main__":
    setup_multitenant_environment()